156	    private static SKBitmap MakeTransparentBlack(SKBitmap bitmap)
157	    {
158	        if (bitmap == null)
159	        {
160	            throw new ArgumentNullException(nameof(bitmap));
161	        }
162	
163	        var workingBitmap = bitmap.IsImmutable
164	            ? new SKBitmap(bitmap.Width, bitmap.Height, bitmap.ColorType, bitmap.AlphaType)
165	            : bitmap;
166	
167	        if (workingBitmap != bitmap)
168	        {
169	            using var canvas = new SKCanvas(workingBitmap);
170	            canvas.DrawBitmap(bitmap, 0, 0);
171	        }
172	
173	        // Get all pixels at once
174	        var colors = workingBitmap.Pixels;
175	        var blackOpaque = new SKColor(0, 0, 0, 255);
176	
177	        for (int i = 0; i < colors.Length; i++)
178	        {
179	            if (colors[i].Alpha < 100)
180	            {
181	                colors[i] = blackOpaque;
182	            }
183	        }
184	
185	        // Set all pixels back at once
186	        workingBitmap.Pixels = colors;
187	
188	        return workingBitmap;
189	    }
