192	    public async Task OcrBatch(OcrEngineType engineType, List<PaddleOcrBatchInput> bitmaps, string language,
193	        string mode, IProgress<PaddleOcrBatchProgress> progress, CancellationToken cancellationToken)
194	    {
195	        string detFilePrefix = MakeDetPrefix(language);
196	        string recFilePrefix = MakeRecPrefix(language);
197	        var detName = GetDetectionName(language, mode);
198	        var recName = GetRecName(language, mode);
199	        _batchProgress = progress;
200	        var folder = Path.Combine(Path.GetTempPath(), Guid.NewGuid().ToString());
201	        Directory.CreateDirectory(folder);
202	        _batchFileNames = new List<PaddleOcrBatchInput>(bitmaps.Count);
203	
204	        var batchFileNamesList = new ConcurrentBag<PaddleOcrBatchInput>();
205	
206	        var parallelOptions = new ParallelOptions
207	        {
208	            CancellationToken = cancellationToken,
209	            MaxDegreeOfParallelism = Environment.ProcessorCount // Adjust as needed
210	        };
211	
212	        await Parallel.ForEachAsync(bitmaps, parallelOptions, async (input, ct) =>
213	        {
214	            SKBitmap? bitmap = null;
215	            SKBitmap? borderedBitmap = null;
216	            try
217	            {
218	                bitmap = input.Bitmap?.Copy() ?? new SKBitmap(1, 1, true);
219	                // bitmap = MakeTransparentBlack(bitmap);
220	                borderedBitmap = CreateDoubleBorder(bitmap, 10, SKColors.Black, new SKColor(0, 0, 0, 0));
221	                var tempImage = Path.Combine(folder, input.Index.ToString("0000") + ".png");
222	                input.FileName = tempImage;
223	                batchFileNamesList.Add(input);
224	
225	                using var image = SKImage.FromBitmap(borderedBitmap);
226	                using var data = image.Encode(SKEncodedImageFormat.Png, 90);
227	                await File.WriteAllBytesAsync(tempImage, data.ToArray(), ct);
228	            }
229	            catch
230	            {
231	                // ignore
232	                return;
233	            }
234	            finally
235	            {
236	                bitmap?.Dispose();
237	                borderedBitmap?.Dispose();
238	            }
239	        });
240	
241	        // Add all processed items back to the original collection
242	        _batchFileNames.AddRange(batchFileNamesList);
243	
244	        var parameters = $"ocr -i \"{folder}\" " +
245	                         "--use_textline_orientation true " +
246	                         "--use_doc_orientation_classify false " +
247	                         "--use_doc_unwarping false " +
248	                         $"--lang {language} " +
249	                         $"--text_detection_model_dir \"{_detPath + Path.DirectorySeparatorChar + detName}\" " +
250	                         $"--text_detection_model_name \"{detName}\" " +
251	                         $"--text_recognition_model_dir \"{_recPath + Path.DirectorySeparatorChar + recName}\" " +
252	                         $"--text_recognition_model_name \"{recName}\" " +
253	                         $"--textline_orientation_model_dir \"{_clsPath + Path.DirectorySeparatorChar + TextlineOrientationModelName}\" " +
254	                         $"--textline_orientation_model_name \"{TextlineOrientationModelName}\"";
255	
256	        var paddleOcrPath = Path.Combine(Se.PaddleOcrFolder, "paddleocr.bin");
257	        if (engineType != OcrEngineType.PaddleOcrStandalone || !File.Exists(paddleOcrPath))
258	        {
259	            paddleOcrPath = "paddleocr";
260	        }
261	
262	        if (engineType == OcrEngineType.PaddleOcrStandalone &&
263	            File.Exists(Path.Combine(Se.PaddleOcrFolder, "paddleocr.exe")))
264	        {
265	            paddleOcrPath = Path.Combine(Se.PaddleOcrFolder, "paddleocr.exe");
266	        }
267	
268	        if (engineType == OcrEngineType.PaddleOcrPython)
269	        {
270	            paddleOcrPath = GetPaddleOcrPytonPath();
271	        }
272	
273	        var process = new Process
274	        {
275	            StartInfo = new ProcessStartInfo
276	            {
277	                FileName = paddleOcrPath,
278	                Arguments = parameters,
279	                UseShellExecute = false,
280	                RedirectStandardOutput = true,
281	                RedirectStandardError = true,
282	                CreateNoWindow = true,
283	            },
284	        };
285	
286	        process.StartInfo.StandardOutputEncoding = Encoding.UTF8;
287	        process.StartInfo.RedirectStandardOutput = true;
288	        process.StartInfo.EnvironmentVariables["PYTHONIOENCODING"] = "utf-8";
289	        process.StartInfo.EnvironmentVariables["PYTHONUTF8"] = "1";
290	        process.OutputDataReceived += OutputHandlerBatch;
291	        _textDetectionResults.Clear();
292	
293	#pragma warning disable CA1416 // Validate platform compatibility
294	        process.Start();
295	#pragma warning restore CA1416 // Validate platform compatibility;
296	
297	        process.BeginOutputReadLine();
298	
299	        await process.WaitForExitAsync(cancellationToken);
300	
301	        if (process.ExitCode != 0)
302	        {
303	            Error = await process.StandardError.ReadToEndAsync(cancellationToken);
304	            Se.LogError($"PaddleOCR failed with exit code {process.ExitCode} and error: {Error}");
305	            return;
306	        }
