309	        {
310	            var input = _batchFileNames.First(p => p.FileName == _batchFileName);
311	            var p = new PaddleOcrBatchProgress
312	            {
313	                Index = input.Index,
314	                Text = MakeResult(_textDetectionResults),
315	                Item = input.Item,
316	            };
317	            _batchProgress?.Report(p);
318	            _textDetectionResults.Clear();
319	        }
320	
321	        try
322	        {
323	            Directory.Delete(folder, true);
324	        }
325	        catch
326	        {
327	            // ignore
328	        }
329	    }
