331	    private static string GetPaddleOcrPytonPath()
332	    {
333	        var possiblePaths = new[]
334	        {
335	            // Windows user install
336	//            Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData), @"Programs\Python"),
337	
338	            // Windows pip scripts dir (per environment)
339	            Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile),
340	                @"AppData\Local\Programs\Python"),
341	
342	            // Mac default Frameworks path
343	            "/Library/Frameworks/Python.framework/Versions",
344	
345	            // Mac Homebrew path
346	            "/usr/local/Cellar/python",
347	            "/opt/homebrew/Cellar/python",
348	
349	            // Conda default paths
350	            Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), "opt", "anaconda3"),
351	            Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), "miniconda3")
352	        };
353	
354	        string executableName;
355	        if (Environment.OSVersion.Platform == PlatformID.Win32NT)
356	        {
357	            executableName = "paddleocr.exe";
358	        }
359	        else
360	        {
361	            executableName = "paddleocr"; // Mac/Linux - no .exe
362	        }
363	
364	        var foundFiles = possiblePaths
365	            .Where(Directory.Exists)
366	            .SelectMany(baseDir => Directory.GetFiles(baseDir, executableName, SearchOption.AllDirectories))
367	            .ToList();
368	
369	        if (foundFiles.Any())
370	        {
371	            var sitePackages = foundFiles
372	                .Where(p => p.Contains("site-packages"))
373	                .OrderByDescending(p => p.Length)
374	                .ToList();
375	            if (sitePackages.Any())
376	            {
377	                return sitePackages.Last();
378	            }
379	
380	            return foundFiles.Last();
381	        }
382	        else
383	        {
384	            return "paddleocr"; // Fallback to just the command name
385	        }
386	    }
