388	    private static SKBitmap CreateDoubleBorder(SKBitmap source, int borderSize, SKColor innerColor, SKColor outerColor)
389	    {
390	        var totalBorder = borderSize * 2;
391	        var finalWidth = source.Width + totalBorder * 2;
392	        var finalHeight = source.Height + totalBorder * 2;
393	
394	        var result = new SKBitmap(finalWidth, finalHeight);
395	        using var canvas = new SKCanvas(result);
396	
397	        // Clear with outer border color
398	        canvas.Clear(outerColor);
399	
400	        // Draw inner border rectangle
401	        using var paint = new SKPaint { Color = innerColor };
402	        canvas.DrawRect(borderSize, borderSize,
403	            finalWidth - borderSize * 2, finalHeight - borderSize * 2, paint);
404	
405	        // Draw original bitmap in center
406	        canvas.DrawBitmap(source, totalBorder, totalBorder);
407	
408	        return result;
409	    }
