461	    public static SKBitmap AddBorder(SKBitmap originalBitmap, int borderWidth, SKColor color)
462	    {
463	        // Calculate new dimensions
464	        int newWidth = originalBitmap.Width + 2 * borderWidth;
465	        int newHeight = originalBitmap.Height + 2 * borderWidth;
466	
467	        // Create a new bitmap with the new dimensions
468	        SKBitmap borderedBitmap = new(newWidth, newHeight);
469	
470	        // Create a canvas to draw on the new bitmap
471	        using (var canvas = new SKCanvas(borderedBitmap))
472	        {
473	            // Fill the canvas with a border color (optional)
474	            var borderColor = color;
475	            canvas.Clear(borderColor);
476	
477	            // Draw the original bitmap onto the canvas, offset by the border width
478	            canvas.DrawBitmap(originalBitmap, borderWidth, borderWidth);
479	        }
480	
481	        return borderedBitmap;
