484	    private string MakeResult(List<PaddleOcrResultParser.TextDetectionResult> textDetectionResults)
485	    {
486	        var sb = new StringBuilder();
487	        var lines = MakeLines(textDetectionResults);
488	        foreach (var line in lines)
489	        {
