497	    private List<List<PaddleOcrResultParser.TextDetectionResult>> MakeLines(
498	        List<PaddleOcrResultParser.TextDetectionResult> input)
499	    {
500	        var result = new List<List<PaddleOcrResultParser.TextDetectionResult>>();
501	        var heightAverage = input.Average(p => p.BoundingBox.Height);
502	        var sorted = input.OrderBy(p => p.BoundingBox.Center.Y);
503	        var line = new List<PaddleOcrResultParser.TextDetectionResult>();
504	        PaddleOcrResultParser.TextDetectionResult? last = null;
505	        foreach (var element in sorted)
506	        {
507	            if (last == null)
508	            {
509	                line.Add(element);
510	            }
511	            else
512	            {
513	                if (element.BoundingBox.Center.Y > last.BoundingBox.TopLeft.Y + heightAverage)
514	                {
515	                    result.Add(line.OrderBy(p => p.BoundingBox.TopLeft.X).ToList());
516	                    line = new List<PaddleOcrResultParser.TextDetectionResult>();
517	                }
518	
519	                line.Add(element);
520	            }
521	
522	            last = element;
523	        }
524	
525	        if (line.Count > 0)
526	        {
527	            result.Add(line.OrderBy(p => p.BoundingBox.TopLeft.X).ToList());
528	        }
529	
530	        return result;
531	    }
