namespace UITests.Features.Ocr;

public class PaddleOcrResultParserTests
{
    [Fact]
    public void Parse_TextWithoutQuotes_ShouldParseCorrectly()
    {
        // Arrange
        var parser = new PaddleOcrResultParser();
        var input = "[[[92.0, 56.0], [735.0, 60.0], [734.0, 118.0], [91.0, 113.0]], ('My mommy always said', 0.9907816052436829)]";

        // Act
        var result = parser.Parse(input);

        // Assert
        Assert.Equal("My mommy always said", result.Text);
        Assert.Equal(0.9907816052436829, result.Confidence);
    }

    [Fact]
    public void Parse_TextWithDoubleQuote_ShouldNotEscapeSingleQuote()
    {
        // Arrange - PaddleOCR wraps in single quotes when text contains double quotes
        // and escapes single quotes within the text
        var parser = new PaddleOcrResultParser();
        var input = @"[[[92.0, 56.0], [735.0, 60.0], [734.0, 118.0], [91.0, 113.0]], ('"" It\'s raining...', 0.9964)]";

        // Act
        var result = parser.Parse(input);

        // Assert - the escaped single quote should be unescaped
        Assert.Equal("\" It's raining...", result.Text);
    }

    [Fact]
    public void Parse_TextWithDoubleQuotes_ShouldParseCorrectly()
    {
        // Arrange
        var parser = new PaddleOcrResultParser();
        var input = @"[[[92.0, 56.0], [735.0, 60.0], [734.0, 118.0], [91.0, 113.0]], (""He said \""Hello\"" today"", 0.9964)]";

        // Act
        var result = parser.Parse(input);

        // Assert
        Assert.Equal("He said \"Hello\" today", result.Text);
    }

    [Fact]
    public void Parse_TextWrappedInDoubleQuotes_ShouldParseCorrectly()
    {
        // Arrange - text wrapped in double quotes
        var parser = new PaddleOcrResultParser();
        var input = "[[[92.0, 56.0], [735.0, 60.0], [734.0, 118.0], [91.0, 113.0]], (\"Hello World\", 0.9964)]";

        // Act
        var result = parser.Parse(input);

        // Assert
        Assert.Equal("Hello World", result.Text);
    }
}

